select count(*) from postgres.comments as c, postgres.posts as p, postgres.votes as v, postgres.users as u where u.id = p.owneruserid and p.id = v.postid and p.id = c.postid and p.score>=0 and p.score<=16 and p.viewcount>=0 and p.creationdate<=timestamp '2014-09-09 12:00:50' and u.reputation>=1 and u.creationdate>=timestamp '2010-07-19 19:08:49' and u.creationdate<=timestamp '2014-08-28 12:15:56';
